import { addFilter } from '@/assets/js/functions/HooksSystem.js';

// Default toolbar buttons
import screenOptionsButton from './buttons/screen-options/index.js';
import helpButton from './buttons/help/index.js';
import viewSiteButton from './buttons/view-site/index.js';
import adminStatusButton from './buttons/admin-status/index.js';

// Register left-side toolbar buttons
addFilter('uixpress/toolbar/render/left', (components) => {
  return [
    ...components,
    adminStatusButton,
  ];
});

// Register right-side toolbar buttons
addFilter('uixpress/toolbar/render/right', (components) => {
  return [
    ...components,
    screenOptionsButton,
    helpButton,
    viewSiteButton,
  ];
});

